+// RegisteredNames returns a set of all currently registered tool names.
+func (r *ToolRegistry) RegisteredNames() map[string]bool {
+	r.mu.RLock()
+	defer r.mu.RUnlock()
+	names := make(map[string]bool, len(r.tools))
+	for name := range r.tools {
+		names[name] = true
+	}
+	return names
+}
